import heapq

class Graph:
    def __init__(self):
        self.graph = {}

    def add_edge(self, u, v, cost):
        if u not in self.graph:
            self.graph[u] = []
        self.graph[u].append((v, cost))

    def get_neighbors(self, node):
        return self.graph.get(node, [])

def heuristic(node, goal):
    # Simple heuristic: assumes nodes are labeled with numbers
    # and calculates absolute difference (can be customized)
    h_values = {
        'A': 6, 'B': 4, 'C': 4, 'D': 2, 'E': 1, 'F': 0
    }
    return h_values.get(node, 0)

def astar(graph, start, goal):
    open_set = []
    heapq.heappush(open_set, (0, start))
    came_from = {}
    g_score = {start: 0}
    f_score = {start: heuristic(start, goal)}

    while open_set:
        _, current = heapq.heappop(open_set)

        if current == goal:
            path = []
            while current in came_from:
                path.append(current)
                current = came_from[current]
            path.append(start)
            return path[::-1]

        for neighbor, cost in graph.get_neighbors(current):
            tentative_g = g_score.get(current, float('inf')) + cost

            if tentative_g < g_score.get(neighbor, float('inf')):
                came_from[neighbor] = current
                g_score[neighbor] = tentative_g
                f_score[neighbor] = tentative_g + heuristic(neighbor, goal)
                heapq.heappush(open_set, (f_score[neighbor], neighbor))

    return None

